import Head from 'next/head'
import { useState, useEffect, useMemo } from 'react'
import wordsData from '../data/words.json'
import styles from '../styles/Home.module.css'

export default function Home() {
  const [currentIndex, setCurrentIndex] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [isLoaded, setIsLoaded] = useState(false)
  const [wordStats, setWordStats] = useState({})

  // Load progress and stats from localStorage on mount
  useEffect(() => {
    const savedStats = localStorage.getItem('wordcard-stats')
    const savedIndex = localStorage.getItem('wordcard-index')
    
    if (savedStats) {
      setWordStats(JSON.parse(savedStats))
    }
    if (savedIndex !== null) {
      const index = parseInt(savedIndex, 10)
      if (index >= 0 && index < wordsData.length) {
        setCurrentIndex(index)
      }
    }
    setIsLoaded(true)
  }, [])

  // Sync stats to localStorage
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('wordcard-stats', JSON.stringify(wordStats))
    }
  }, [wordStats, isLoaded])

  // Sync index to localStorage
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('wordcard-index', currentIndex.toString())
    }
  }, [currentIndex, isLoaded])

  const currentWord = wordsData[currentIndex]
  const currentStat = wordStats[currentWord?.japanese] || { level: 0, lastReview: 0 }

  const nextWord = () => {
    setCurrentIndex((currentIndex + 1) % wordsData.length)
    setShowAnswer(false)
  }

  const prevWord = () => {
    setCurrentIndex((currentIndex - 1 + wordsData.length) % wordsData.length)
    setShowAnswer(false)
  }

  const handleFeedback = (remembered) => {
    const wordKey = currentWord.japanese
    const now = Date.now()
    const newLevel = remembered ? Math.min(currentStat.level + 1, 5) : 0
    
    setWordStats(prev => ({
      ...prev,
      [wordKey]: {
        level: newLevel,
        lastReview: now
      }
    }))
    
    // Automatically move to next word after a short delay
    setTimeout(() => {
      nextWord()
    }, 300)
  }

  const toggleFlip = () => setShowAnswer(!showAnswer)

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      toggleFlip()
    }
  }

  if (!wordsData || wordsData.length === 0) {
    return <div className={styles.container}>暂无单词数据</div>
  }

  if (!isLoaded) return null

  return (
    <div className={styles.container}>
      <Head>
        <title>师傅的购物单词本 - 记忆曲线版</title>
      </Head>
      
      <h1 className={styles.title}>🧠 记忆曲线单词本</h1>
      
      {currentStat.level === 5 && (
        <div className={styles.masteredBadge}>✨ 已掌握 (Level 5)</div>
      )}

      <div className={styles.levelIndicator}>
        {[1, 2, 3, 4, 5].map(lvl => (
          <div 
            key={lvl} 
            className={`${styles.levelDot} ${currentStat.level >= lvl ? styles.levelDotActive : ''}`}
          />
        ))}
      </div>

      <div 
        role="button"
        tabIndex={0}
        aria-label={`单词卡片: ${currentWord.japanese}. 点击或按空格键翻转`}
        onKeyDown={handleKeyDown}
        onClick={toggleFlip}
        className={`${styles.card} ${showAnswer ? styles.cardFlipped : ''}`}
      >
        <h2 className={styles.wordJapanese}>{currentWord.japanese}</h2>
        <p className={styles.wordKana}>{currentWord.kana}</p>
        
        {showAnswer ? (
          <div className={styles.answerArea}>
            <p className={styles.wordChinese}>{currentWord.chinese}</p>
            <p className={styles.wordEnglish}>{currentWord.english}</p>
            <small className={styles.wordSource}>来源: {currentWord.source}</small>
          </div>
        ) : (
          <p className={styles.hint}>点击或按空格查看释义</p>
        )}
      </div>
      
      {showAnswer ? (
        <div className={styles.feedbackGroup}>
          <button 
            onClick={() => handleFeedback(false)}
            className={`${styles.button} ${styles.buttonForgot}`}
          >
            ❌ 没记住 (Level 0)
          </button>
          <button 
            onClick={() => handleFeedback(true)}
            className={`${styles.button} ${styles.buttonRemember}`}
          >
            ✅ 记住了 (Level +1)
          </button>
        </div>
      ) : (
        <div className={styles.buttonGroup}>
          <button 
            onClick={prevWord}
            className={`${styles.button} ${styles.buttonSecondary}`}
          >
            ← 上一个
          </button>
          <button 
            onClick={nextWord}
            className={`${styles.button} ${styles.buttonPrimary}`}
          >
            下一个 →
          </button>
        </div>
      )}

      <div className={styles.progress}>
        进度: {currentIndex + 1} / {wordsData.length}
      </div>
      
      <footer className={styles.footer}>
        <p>掌握 5 个 Level 即视为“已掌握”。数据存储在本地浏览器中。</p>
      </footer>
    </div>
  )
}
